const now = new Date();
const horaUTC = now.getUTCHours();
const horaLima = (horaUTC - 5 + 24) % 24;
const diaSemana = now.getUTCDay();

const esHoroscopo = (diaSemana === 1 && horaLima === 9);

// ─── TONO por hora ───────────────────────────────────────────────────
let tono, intensidad;
if (esHoroscopo) {
  tono = 'horoscopo';
  intensidad = 'horoscopo';
} else if (horaLima === 13) {
  tono = 'humor adulto atrevido con doble sentido fuerte, confesiones comprometedoras, situaciones coquetas de doble lectura, insinuante e inteligente, para audiencia 18+';
  intensidad = 'medio';
} else {
  tono = 'humor adulto muy picante, doble sentido directo y atrevido, confesiones atrevidas, remates inesperados, preguntas que dejan volar la imaginación, sin ser explícito, para audiencia 18+';
  intensidad = 'picante';
}

// ─── ESTILO DE IMAGEN por día ────────────────────────────────────────
const estilos = [
  { dia: 'Domingo',   estilo: 'digital painting fantasy art',  artistico: 'vibrant fantasy digital painting, painterly strokes, cinematic lighting' },
  { dia: 'Lunes',     estilo: 'photorealistic',                artistico: 'hyperrealistic photography, 8k resolution, professional lighting, sharp details' },
  { dia: 'Martes',    estilo: 'anime illustration',            artistico: 'high quality anime art style, detailed manga illustration, vibrant colors' },
  { dia: 'Miercoles', estilo: 'pin-up vintage art',            artistico: 'classic 1950s pin-up art style, saturated colors, retro aesthetic, Gil Elvgren style' },
  { dia: 'Jueves',    estilo: 'semi-realistic digital art',    artistico: 'semi-realistic digital art, between photo and illustration, dramatic lighting' },
  { dia: 'Viernes',   estilo: 'western comic art',             artistico: 'western comic book art style, bold lines, vibrant colors, dynamic composition' },
  { dia: 'Sabado',    estilo: 'pixel art',                     artistico: 'detailed 16-bit pixel art style, retro video game aesthetic, colorful sprites' }
];

// ─── LOCACIÓN por día ────────────────────────────────────────────────
const locaciones = [
  { lugar: 'terraza penthouse',    escenario: 'luxury penthouse rooftop terrace, panoramic city view, sunset sky, elegant outdoor furniture' },
  { lugar: 'piscina infinity',     escenario: 'luxury infinity pool overlooking the ocean, turquoise water, tropical surroundings, daylight' },
  { lugar: 'playa privada',        escenario: 'exclusive private beach, golden sand, crystal clear water, golden hour sunset lighting' },
  { lugar: 'yate de lujo',         escenario: 'luxury yacht deck, open sea, warm sunlight, elegant marine setting' },
  { lugar: 'hotel boutique',       escenario: 'luxury boutique hotel room, floor-to-ceiling windows, city view, sophisticated interior' },
  { lugar: 'bar rooftop',          escenario: 'trendy rooftop bar, city lights at night, ambient lighting, urban luxury setting' },
  { lugar: 'jacuzzi exterior',     escenario: 'outdoor jacuzzi, night setting, soft ambient lighting, steam, luxury resort' }
];

// ─── ROPA por estilo ─────────────────────────────────────────────────
const ropaPorEstilo = {
  'photorealistic':              'wearing a luxury designer string bikini, wet skin glistening',
  'anime illustration':          'wearing a stylish anime-style beach outfit, crop top and high waist shorts',
  'pin-up vintage art':          'wearing a classic retro pin-up swimsuit, high waist bottom and halter top',
  'semi-realistic digital art':  'wearing a sheer cover-up over a bikini, elegant and sensual',
  'western comic art':           'wearing a fitted superhero-inspired swimsuit, bold colors',
  'pixel art':                   'wearing a retro-style pixel swimsuit, colorful and playful',
  'digital painting fantasy art':'wearing an elegant fantasy-inspired draped dress, ethereal and sensual'
};

const { dia, estilo, artistico } = estilos[diaSemana];
const { lugar, escenario } = locaciones[diaSemana];
const ropa = ropaPorEstilo[estilo];

// ─── CTA por intensidad ──────────────────────────────────────────────
const ctas = {
  medio: [
    '😏 ¿Te suena familiar? Etiqueta a quien te entiende',
    '👀 ¿Verdad o mentira? Comenta sin mentir',
    '🔥 Etiqueta al cómplice que sabe de qué hablas'
  ],
  picante: [
    '😈 Comenta el número sin dar explicaciones 🔥',
    '💋 ¿Culpable o inocente? Solo tú lo sabes',
    '🔥 Etiqueta a quien le llegó este mensaje directo'
  ],
  horoscopo: [
    '🔮 Comenta tu signo y etiqueta a tu cómplice del zodiaco 😏',
    '⭐ ¿Te identificas? Comenta y etiqueta al culpable 😈',
    '🌙 Comenta tu signo sin explicar por qué te quedaste callado/a 😂'
  ]
};

const listaCtas = ctas[intensidad];
const cta = listaCtas[Math.floor(Math.random() * listaCtas.length)];

return [{
  json: {
    hora: horaLima,
    dia, diaSemana,
    tono, intensidad,
    estilo, artistico,
    lugar, escenario, ropa,
    cta, esHoroscopo,
    timestamp: now.toISOString()
  }
}];

const datos = $input.first().json;

let systemPrompt, userPrompt;

if (datos.esHoroscopo) {
  systemPrompt = `Eres un experto en humor adulto latinoamericano para redes sociales. Creas horóscopos pícaros, atrevidos y con doble sentido fuerte para audiencia adulta 18+. Cada predicción es corta, sugerente, con doble lectura inteligente. SIEMPRE respondes ÚNICAMENTE con JSON válido, sin backticks, sin markdown.`;

  userPrompt = `Crea el horóscopo pícaro semanal. Cada signo tiene UNA predicción de máximo 10 palabras, con doble sentido atrevido, insinuante e inteligente. En español latinoamericano.

Responde SOLO con este JSON:
{
  "chiste": "♈ ARIES: [predicción]\n♉ TAURO: [predicción]\n♊ GÉMINIS: [predicción]\n♋ CÁNCER: [predicción]\n♌ LEO: [predicción]\n♍ VIRGO: [predicción]\n♎ LIBRA: [predicción]\n♏ ESCORPIO: [predicción]\n♐ SAGITARIO: [predicción]\n♑ CAPRICORNIO: [predicción]\n♒ ACUARIO: [predicción]\n♓ PISCIS: [predicción]",
  "caption": "🔮 EL HORÓSCOPO DE LA SEMANA llegó... y el universo sabe más de ti de lo que crees. 😏\n\n[los 12 signos aquí]",
  "situacion_imagen": "mysterious and seductive astrologer, sensual and confident expression, looking directly at camera with a knowing smile",
  "hashtags": "#Horoscopo #HumorAdulto #BellezasConPicardia #Zodiaco #HumorLatino"
}`;

} else {
  systemPrompt = `Eres un experto en humor adulto latinoamericano viral para redes sociales. Generas contenido muy atrevido con doble sentido fuerte e inteligente, confesiones comprometedoras, remates inesperados y preguntas que hacen volar la imaginación. NUNCA eres explícito ni vulgar — el poder está en la insinuación inteligente. Audiencia 18+. SIEMPRE respondes ÚNICAMENTE con JSON válido, sin backticks, sin markdown.`;

  userPrompt = `Genera un chiste/confesión de humor adulto con tono: ${datos.tono}

Formatos posibles (elige el más viral):
- Confesión comprometedora: "Confieso que cuando [situación inocente]... [remate con doble sentido]"
- Remate inesperado: setup inocente de 2 líneas + golpe final atrevido
- Pregunta sin respuesta: pregunta que deja volar la imaginación del lector
- Situación de 'te pillé': momento de complicidad vergonzosa

Reglas:
- Máximo 3 líneas
- Doble sentido fuerte pero inteligente, no vulgar
- Que genere comentarios y etiquetas
- En español latinoamericano natural

También extrae la situación específica del chiste para generar la imagen relacionada.

Responde SOLO con este JSON:
{
  "chiste": "texto del chiste (máximo 3 líneas)",
  "caption": "chiste completo con emoji que amplifica el doble sentido (máximo 220 caracteres)",
  "situacion_imagen": "descripción en inglés de la expresión/actitud/pose de la mujer que conecta con el chiste (máximo 20 palabras)",
  "hashtags": "#HumorAdulto #BellezasConPicardia #DoubleMeaning #HumorLatino #Picardía"
}`;
}

return [{ json: { ...datos, systemPrompt, userPrompt } }];

const response = $input.first().json;
const variables = $('Construye Prompt según Tipo').first().json;

let contenido;
try {
  const rawText = response.choices[0].message.content;
  const cleaned = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  contenido = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Error parseando JSON de OpenRouter: ' + e.message);
}

// ─── Construir prompt de imagen CONECTADO al chiste ──────────────────
const situacionImagen = contenido.situacion_imagen || 'confident and seductive expression, looking at camera';

let promptImagen;
if (variables.esHoroscopo) {
  promptImagen = `sexy adult woman 25-35 years old, full body shot, ${variables.ropa}, ${situacionImagen}, ${variables.escenario}, ${variables.artistico}, high quality, tasteful but provocative, alluring, no nudity, no explicit content`;
} else {
  promptImagen = `sexy adult woman 25-35 years old, full body shot, ${variables.ropa}, ${situacionImagen}, ${variables.escenario}, ${variables.artistico}, high quality, tasteful but provocative, alluring, no nudity, no explicit content`;
}

// Caption final
const captionFinal = contenido.caption + '\n\n' + variables.cta + '\n\n' + contenido.hashtags;

return [{
  json: {
    ...variables,
    chiste: contenido.chiste,
    caption: captionFinal,
    situacion_imagen: situacionImagen,
    prompt_imagen: promptImagen,
    hashtags: contenido.hashtags
  }
}];

const falResponse = $input.first().json;
const datos = $('Parsea + Construye Prompt Imagen').first().json;

let imageUrl;
try {
  imageUrl = falResponse.images[0].url;
} catch(e) {
  throw new Error('fal.ai no devolvió imagen: ' + JSON.stringify(falResponse));
}

return [{ json: { ...datos, image_url: imageUrl } }];

const datos = $('Extrae URL Imagen').first().json;
const fbResponse = $('Facebook — Publica Post').first().json;
const tipo = datos.esHoroscopo ? '🔮 HORÓSCOPO' : `💬 CHISTE ${datos.intensidad.toUpperCase()}`;

console.log(`✅ Post publicado — ${tipo}`);
console.log(`📅 Día: ${datos.dia} | ⏰ Hora: ${datos.hora}h | 🎨 Estilo: ${datos.estilo} | 📍 Lugar: ${datos.lugar}`);
console.log(`🎭 Situación imagen: ${datos.situacion_imagen}`);
console.log(`📸 Imagen: ${datos.image_url}`);
console.log(`📘 Facebook Post ID: ${fbResponse.id || 'N/A'}`);

return [{ json: { status: 'ok', tipo, facebook_post_id: fbResponse.id, image_url: datos.image_url } }];
